{"content":"1: import type { FeatureId } from "@calcom/features/flags/config";
2: import type { OptInFeaturePolicy, OptInFeatureScope } from "./types";
3: 
4: export interface OptInFeatureConfig {
5:   slug: FeatureId;
6:   titleI18nKey: string;
7:   descriptionI18nKey: string;
8:   policy: OptInFeaturePolicy;
9:   /** Scopes where this feature can be configured. Defaults to all scopes if not specified. */
10:   scope?: OptInFeatureScope[];
11: }
12: 
13: /** All available scopes for feature opt-in configuration */
14: export const ALL_SCOPES: OptInFeatureScope[] = ["org", "team", "user"];
15: 
16: /**
17:  * Features that appear in opt-in settings.
18:  * Add new features here to make them available for user/team opt-in.
19:  */
20: export const OPT_IN_FEATURES: OptInFeatureConfig[] = [
21:   // Example - to be populated with actual features
22:   // {
23:   //   slug: "bookings-v3",
24:   //   titleI18nKey: "bookings_v3_title",
25:   //   descriptionI18nKey: "bookings_v3_description",
26:   //   policy: "permissive",
27:   //   scope: ["org", "team", "user"], // Optional: defaults to all scopes if not specified
28:   // },
29: ];
30: 
31: /**
32:  * Get the configuration for a specific opt-in feature by slug.
33:  */
34: export function getOptInFeatureConfig(slug: string): OptInFeatureConfig | undefined {
35:   return OPT_IN_FEATURES.find((f) => f.slug === slug);
36: }
37: 
38: /**
39:  * Check if a slug is in the opt-in allowlist.
40:  * Acts as a type guard, narrowing the slug to FeatureId when true.
41:  */
42: export function isOptInFeature(slug: string): slug is FeatureId {
43:   return OPT_IN_FEATURES.some((f) => f.slug === slug);
44: }
45: 
46: /**
47:  * Check if there are any opt-in features available.
48:  */
49: export const HAS_OPT_IN_FEATURES: boolean = OPT_IN_FEATURES.length > 0;
50: 
51: /** Whether there are opt-in features available for the user scope */
52: export const HAS_USER_OPT_IN_FEATURES: boolean = OPT_IN_FEATURES.some((f) => !f.scope || f.scope.includes("user"));
53: 
54: /** Whether there are opt-in features available for the team scope */
55: export const HAS_TEAM_OPT_IN_FEATURES: boolean = OPT_IN_FEATURES.some((f) => !f.scope || f.scope.includes("team"));
56: 
57: /** Whether there are opt-in features available for the org scope */
58: export const HAS_ORG_OPT_IN_FEATURES: boolean = OPT_IN_FEATURES.some((f) => !f.scope || f.scope.includes("org"));
59: 
60: /**
61:  * Get opt-in features that are available for a specific scope.
62:  * Features without a scope field are available for all scopes.
63:  */
64: export function getOptInFeaturesForScope(scope: OptInFeatureScope): OptInFeatureConfig[] {
65:   return OPT_IN_FEATURES.filter((f) => !f.scope || f.scope.includes(scope));
66: }
67: 
68: /**
69:  * Check if a feature is allowed for a specific scope.
70:  * Features without a scope field are allowed for all scopes.
71:  * Features not in the config are NOT allowed (must be explicitly configured).
72:  */
73: export function isFeatureAllowedForScope(slug: string, scope: OptInFeatureScope): boolean {
74:   const config = getOptInFeatureConfig(slug);
75:   if (!config) return false;
76:   return !config.scope || config.scope.includes(scope);
77: }
